import anthropic, json

client = anthropic.Anthropic()

tools = [
    {
        "name": "get_stock_price",
        "description": "Get the current market price for a stock ticker. Use when the user asks about a stock price, current value, or market data.",
        "input_schema": {
            "type": "object",
            "properties": {
                "ticker": {"type": "string", "description": "Stock ticker symbol, e.g. AAPL"}
            },
            "required": ["ticker"]
        }
    }
]

# --- Scenario A: model calls the tool ---
response_a = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=512,
    tools=tools,
    messages=[{"role": "user", "content": "What is Apple's stock price right now?"}]
)
print(response_a.stop_reason)      # "tool_use"
for block in response_a.content:
    print(block.type, getattr(block, "name", ""))  # "tool_use  get_stock_price"

# --- Scenario B: model answers without calling the tool ---
response_b = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=512,
    tools=tools,
    messages=[{"role": "user", "content": "What does AAPL stand for?"}]
)
print(response_b.stop_reason)      # "end_turn"
print(response_b.content[0].text)  # "AAPL is the ticker symbol for Apple Inc."

# Tool descriptions directly control when the model reaches for a tool.

# VAGUE — model often skips the tool because it is unsure when to use it
vague_tool = {
    "name": "lookup",
    "description": "Looks things up.",
    "input_schema": {
        "type": "object",
        "properties": {"query": {"type": "string"}},
        "required": ["query"]
    }
}

# PRECISE — model knows exactly when to call
precise_tool = {
    "name": "search_knowledge_base",
    "description": (
        "Search the internal knowledge base for answers to product and policy questions. "
        "Use this before answering any question about pricing, refund policy, "
        "shipping times, or product specifications. Do not answer from memory — "
        "always search first when these topics arise."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "query": {
                "type": "string",
                "description": "The user's question as a short search query"
            }
        },
        "required": ["query"]
    }
}

# The model may decide to call multiple tools in a single turn
# when it determines the goals are independent and can be fulfilled in parallel.

tools_multi = [
    {
        "name": "get_weather",
        "description": "Get current weather for a city.",
        "input_schema": {"type": "object", "properties": {"city": {"type": "string"}}, "required": ["city"]}
    },
    {
        "name": "get_news",
        "description": "Get recent news headlines for a topic.",
        "input_schema": {"type": "object", "properties": {"topic": {"type": "string"}}, "required": ["topic"]}
    }
]

response = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=1024,
    tools=tools_multi,
    messages=[{"role": "user", "content": "What is the weather in London and what is the latest news about AI?"}]
)

tool_use_blocks = [b for b in response.content if b.type == "tool_use"]
print(len(tool_use_blocks))   # 2 — model decided both tools are needed
for b in tool_use_blocks:
    print(b.name, b.input)
# get_weather  {"city": "London"}
# get_news     {"topic": "AI"}
